+// Core Hashi (Bridges) puzzle logic.
+// Bridges are stored as Map<string, number> keyed by canonical "x1,y1,x2,y2" (grid units),
+// where (x1,y1) is lexicographically <= (x2,y2). Value is 1 or 2.
+
+export const ERR_NON_ADJACENT = 'Cannot connect non-adjacent islands';
+export const ERR_MAX_PER_PAIR = 'Max 2 bridges per pair';
+export const ERR_EXCEED_ISLAND = 'Island would exceed its number';
+export const ERR_CROSSING = 'Bridges would cross';
+
+function cmpPoint(a, b) {
+  if (a.x !== b.x) return a.x - b.x;
+  return a.y - b.y;
+}
+
+export function bridgeKey(from, to) {
+  const a = { x: from.x, y: from.y };
+  const b = { x: to.x, y: to.y };
+  const [p1, p2] = cmpPoint(a, b) <= 0 ? [a, b] : [b, a];
+  return `${p1.x},${p1.y},${p2.x},${p2.y}`;
+}
+
+export function parseBridgeKey(key) {
+  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
+  return { x1, y1, x2, y2 };
+}
+
+function isAxisAligned(a, b) {
+  return a.x === b.x || a.y === b.y;
+}
+
+function between(v, a, b) {
+  const min = Math.min(a, b);
+  const max = Math.max(a, b);
+  return v > min && v < max;
+}
+
+function buildIslandLookup(islands) {
+  const byId = new Map();
+  const byCoord = new Map();
+  for (const isl of islands) {
+    byId.set(isl.id, isl);
+    byCoord.set(`${isl.x},${isl.y}`, isl);
+  }
+  return { byId, byCoord };
+}
+
+// Two segments cross if one is vertical and the other horizontal and their interiors intersect.
+function segmentsCross(segA, segB) {
+  // seg: {x1,y1,x2,y2}
+  const aVertical = segA.x1 === segA.x2;
+  const bVertical = segB.x1 === segB.x2;
+  if (aVertical === bVertical) return false; // parallel
+
+  const v = aVertical ? segA : segB;
+  const h = aVertical ? segB : segA;
+
+  // Proper crossing must be strictly inside both segments (not at endpoints).
+  const x = v.x1;
+  const y = h.y1;
+  const inV = between(y, v.y1, v.y2);
+  const inH = between(x, h.x1, h.x2);
+  return inV && inH;
+}
+
+export function wouldCross(bridges, from, to) {
+  const candidate = { x1: from.x, y1: from.y, x2: to.x, y2: to.y };
+  for (const [k, count] of bridges.entries()) {
+    if (!count) continue;
+    const existing = parseBridgeKey(k);
+    if (segmentsCross(candidate, existing)) return true;
+  }
+  return false;
+}
+
+// Returns true only if to is the nearest island to from in that cardinal direction with no island between.
+export function areAdjacent(islands, from, to) {
+  if (from.id === to.id) return false;
+  if (!isAxisAligned(from, to)) return false;
+
+  if (from.x === to.x) {
+    const x = from.x;
+    const dir = Math.sign(to.y - from.y);
+    if (dir === 0) return false;
+    let best = null;
+    let bestDist = Infinity;
+    for (const isl of islands) {
+      if (isl.id === from.id) continue;
+      if (isl.x !== x) continue;
+      const d = isl.y - from.y;
+      if (Math.sign(d) !== dir) continue;
+      const ad = Math.abs(d);
+      if (ad < bestDist) {
+        bestDist = ad;
+        best = isl;
+      }
+    }
+    return best?.id === to.id;
+  }
+
+  // horizontal
+  const y = from.y;
+  const dir = Math.sign(to.x - from.x);
+  if (dir === 0) return false;
+  let best = null;
+  let bestDist = Infinity;
+  for (const isl of islands) {
+    if (isl.id === from.id) continue;
+    if (isl.y !== y) continue;
+    const d = isl.x - from.x;
+    if (Math.sign(d) !== dir) continue;
+    const ad = Math.abs(d);
+    if (ad < bestDist) {
+      bestDist = ad;
+      best = isl;
+    }
+  }
+  return best?.id === to.id;
+}
+
+export function computeCurrentCounts(islands, bridges) {
+  const counts = new Map();
+  for (const isl of islands) counts.set(isl.id, 0);
+
+  // For each bridge, add its count to both endpoints.
+  const { byCoord } = buildIslandLookup(islands);
+  for (const [k, n] of bridges.entries()) {
+    if (!n) continue;
+    const { x1, y1, x2, y2 } = parseBridgeKey(k);
+    const a = byCoord.get(`${x1},${y1}`);
+    const b = byCoord.get(`${x2},${y2}`);
+    if (!a || !b) continue;
+    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
+    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
+  }
+  return counts;
+}
+
+export function canAddBridge(islands, bridges, from, to, delta) {
+  // delta is +1 or -1 relative change (used for cycling or removal).
+  if (!areAdjacent(islands, from, to)) {
+    return { valid: false, error: ERR_NON_ADJACENT };
+  }
+  const key = bridgeKey(from, to);
+  const existing = bridges.get(key) ?? 0;
+  const next = existing + delta;
+
+  if (next < 0) return { valid: true, error: null };
+  if (next > 2) return { valid: false, error: ERR_MAX_PER_PAIR };
+  if (next === 0) {
+    // Removing never creates crossing / exceed errors.
+    return { valid: true, error: null };
+  }
+
+  // Crossing check only when adding (existing==0 or 1 and delta==+1).
+  if (delta > 0 && wouldCross(bridges, from, to)) {
+    return { valid: false, error: ERR_CROSSING };
+  }
+
+  // Island capacity check.
+  const counts = computeCurrentCounts(islands, bridges);
+  const fromCount = counts.get(from.id) ?? 0;
+  const toCount = counts.get(to.id) ?? 0;
+
+  if (delta > 0) {
+    if (fromCount + 1 > from.value || toCount + 1 > to.value) {
+      return { valid: false, error: ERR_EXCEED_ISLAND };
+    }
+  }
+
+  return { valid: true, error: null };
+}
+
+export function checkConnectivity(islands, bridges) {
+  if (islands.length === 0) return true;
+  const { byCoord } = buildIslandLookup(islands);
+
+  const adj = new Map();
+  for (const isl of islands) adj.set(isl.id, []);
+
+  for (const [k, n] of bridges.entries()) {
+    if (!n) continue;
+    const { x1, y1, x2, y2 } = parseBridgeKey(k);
+    const a = byCoord.get(`${x1},${y1}`);
+    const b = byCoord.get(`${x2},${y2}`);
+    if (!a || !b) continue;
+    adj.get(a.id).push(b.id);
+    adj.get(b.id).push(a.id);
+  }
+
+  const startId = islands[0].id;
+  const seen = new Set([startId]);
+  const stack = [startId];
+  while (stack.length) {
+    const cur = stack.pop();
+    for (const nxt of adj.get(cur) ?? []) {
+      if (!seen.has(nxt)) {
+        seen.add(nxt);
+        stack.push(nxt);
+      }
+    }
+  }
+
+  return seen.size === islands.length;
+}
+
+export function isVictory(islands, bridges) {
+  // Ensure counts match exactly.
+  const counts = computeCurrentCounts(islands, bridges);
+  for (const isl of islands) {
+    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
+  }
+  // No crossings.
+  for (const [k1, n1] of bridges.entries()) {
+    if (!n1) continue;
+    const s1 = parseBridgeKey(k1);
+    for (const [k2, n2] of bridges.entries()) {
+      if (!n2) continue;
+      if (k1 >= k2) continue;
+      const s2 = parseBridgeKey(k2);
+      if (segmentsCross(s1, s2)) return false;
+    }
+  }
+  // Connected.
+  return checkConnectivity(islands, bridges);
+}
+
