+  function applyBridgeDelta(from, to, delta) {
+    const res = canAddBridge(islands, bridges, from, to, delta);
+    if (!res.valid) {
+      setError(res.error);
+      return false;
+    }
+    setBridges((prev) => {
+      const next = new Map(prev);
+      const k = bridgeKey(from, to);
+      const existing = next.get(k) ?? 0;
+      const v = existing + delta;
+      if (v <= 0) next.delete(k);
+      else next.set(k, v);
+      return next;
+    });
+    clearErrorOnValid(true);
+    return true;
+  }
+
+  function cycleBridge(from, to) {
+    // none -> single -> double -> none
+    const k = bridgeKey(from, to);
+    const existing = bridges.get(k) ?? 0;
+    if (existing === 0) return applyBridgeDelta(from, to, +1);
+    if (existing === 1) return applyBridgeDelta(from, to, +1);
+    // existing === 2
+    // remove entirely
+    return applyBridgeDelta(from, to, -2);
+  }
+
+  function removeBridgeEntirely(from, to) {
+    const k = bridgeKey(from, to);
+    const existing = bridges.get(k) ?? 0;
+    if (existing <= 0) return false;
+    setBridges((prev) => {
+      const next = new Map(prev);
+      next.delete(k);
+      return next;
+    });
+    setError(null);
+    return true;
+  }
+
+  function onIslandClick(e, isl) {
+    // Ctrl+click removes existing bridge between selected and this, if any.
+    if (e.ctrlKey && selectedId != null && selectedId !== isl.id) {
