+} from './utils/hashiLogic';
+
+const GRID = 40;
+const SVG_W = 800;
+const SVG_H = 600;
+
+function islandPx(isl) {
+  return { cx: isl.x * GRID, cy: isl.y * GRID };
+}
+
+function pickInitialCursor(islands) {
+  return islands.length ? islands[0].id : null;
+}
+
+function findIslandById(islands, id) {
+  return islands.find((i) => i.id === id) ?? null;
+}
+
+function findNextIslandInDirection(islands, from, dir) {
+  // dir: 'left'|'right'|'up'|'down'
+  let best = null;
+  let bestDist = Infinity;
+  for (const isl of islands) {
+    if (isl.id === from.id) continue;
+    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
+      const d = from.x - isl.x;
+      if (d < bestDist) {
+        bestDist = d;
+        best = isl;
+      }
+    }
+    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
+      const d = isl.x - from.x;
+      if (d < bestDist) {
+        bestDist = d;
+        best = isl;
+      }
+    }
+    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
+      const d = from.y - isl.y;
+      if (d < bestDist) {
+        bestDist = d;
+        best = isl;
+      }
+    }
+    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
+      const d = isl.y - from.y;
+      if (d < bestDist) {
+        bestDist = d;
+        best = isl;
+      }
+    }
+  }
+  return best;
+}
+
+function computeBridgeLines(islands, bridges) {
+  // Returns array of { key, idx, x1,y1,x2,y2 } in *pixels*; idx differentiates double lines.
+  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));
+  const lines = [];
+  for (const [k, n] of bridges.entries()) {
+    if (!n) continue;
+    const [x1, y1, x2, y2] = k.split(',').map((v) => Number(v));
+    const a = byCoord.get(`${x1},${y1}`);
+    const b = byCoord.get(`${x2},${y2}`);
+    if (!a || !b) continue;
+
+    const p1 = islandPx(a);
+    const p2 = islandPx(b);
+
+    if (n === 1) {
+      lines.push({ key: k, idx: 0, x1: p1.cx, y1: p1.cy, x2: p2.cx, y2: p2.cy });
+    } else {
+      // Offset two parallel lines by 4px from centerline.
+      const off = 4;
+      const horizontal = a.y === b.y;
+      if (horizontal) {
+        lines.push({ key: k, idx: 0, x1: p1.cx, y1: p1.cy - off, x2: p2.cx, y2: p2.cy - off });
+        lines.push({ key: k, idx: 1, x1: p1.cx, y1: p1.cy + off, x2: p2.cx, y2: p2.cy + off });
+      } else {
+        lines.push({ key: k, idx: 0, x1: p1.cx - off, y1: p1.cy, x2: p2.cx - off, y2: p2.cy });
+        lines.push({ key: k, idx: 1, x1: p1.cx + off, y1: p1.cy, x2: p2.cx + off, y2: p2.cy });
+      }
+    }
+  }
+  return lines;
+}
